compliant:
#include <cmath>

float a = 0.1f;
float b = 0.2f;
float c = 0.3f;
float epsilon = 1e-5f;

if (std::abs(a + b - c) < epsilon) { // Compliant - use epsilon comparison
  // Safe floating point comparison
}

double x = 1.0/3.0;
double y = 1.0/3.0;
double tolerance = 1e-9;
if (std::abs(x - y) < tolerance) { // Compliant - tolerance-based comparison
  // Safe comparison with tolerance
}
